const input = $input.first().json.body || $input.first().json;

const name = (input.name || '').trim();
const email = (input.email || '').trim().toLowerCase();
const phone = (input.phone || '').trim();
const service = (input.service || '').trim();
const budget = (input.budget || '').trim();
const message = (input.message || '').trim();
const howHeard = (input['how-heard'] || input.how_heard || '').trim();
const leadMagnet = input.lead_magnet === true || input.lead_magnet === 'true';
const submittedAt = input.submitted_at || new Date().toISOString();

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  throw new Error('Invalid email address: ' + email);
}

const leadId = 'DA-' + Date.now().toString(36).toUpperCase();

return [{ json: {
  lead_id: leadId,
  name, email, phone, service, budget, message,
  how_heard: howHeard,
  lead_magnet: leadMagnet,
  submitted_at: submittedAt,
  source: leadMagnet ? 'lead_magnet' : 'contact_form'
}}];

// Fetch brain files from public GitHub raw: Layer 1 (Context) at runtime.
const base = 'https://raw.githubusercontent.com/isaiahwong-bit/Digital-Artifacts/main/brain';
const files = ['icp', 'pricing', 'company-brief', 'tone-of-voice', 'response-scaffolds', 'integrations'];

const fetched = await Promise.all(files.map(async (f) => {
  const res = await fetch(`${base}/${f}.md`);
  if (!res.ok) throw new Error(`Failed to fetch ${f}.md: ${res.status}`);
  return [f, await res.text()];
}));

const brain = Object.fromEntries(fetched);

return [{ json: { ...$input.first().json, brain: {
  icp: brain['icp'],
  pricing: brain['pricing'],
  company: brain['company-brief'],
  tone: brain['tone-of-voice'],
  scaffolds: brain['response-scaffolds'],
  integrations: brain['integrations']
}}}];

