// Parse draft JSON and swap booking link placeholder from brain/integrations.md.
const prev = $('Parse Classification + Mode').item.json;
const raw = $input.first().json?.content?.[0]?.text || '';
let draft;
try {
  const jsonText = raw.trim().replace(/^```json\n?|```$/g, '');
  draft = JSON.parse(jsonText);
} catch (e) {
  draft = {
    subject: 'Got your message',
    body_plain: `${(prev.name||'there').split(' ')[0]},\n\nGot your message, reading it properly shortly and will be back to you.\n\nIsaiah`,
    scaffold_used: 'D', confidence: 'low',
    notes_for_isaiah: 'Claude response unparseable, fallback draft used. Review before approve.'
  };
}

// Pull booking link from integrations.md (default placeholder if not set).
const bookingMatch = (prev.brain?.integrations || '').match(/https:\/\/calendar\.app\.google\/[A-Za-z0-9_-]+/);
const bookingLink = bookingMatch ? bookingMatch[0] : 'https://calendar.app.google/PLACEHOLDER';

draft.body_plain = (draft.body_plain || '').replace(/\{\{\s*BOOKING_LINK\s*\}\}/g, bookingLink);
draft.body_plain = draft.body_plain.replace(/—|–/g, ',');

return [{ json: { ...prev, draft } }];

// Build Telegram brief text for Isaiah (Layer 2 skill: telegram-brief).
// Out-of-hours variant: message is FYI only, no buttons — reply already sent.
const d = $('Parse Draft + Inject Booking Link').item.json;
const c = d.classification;
const prio = c.priority === 1 ? '🔥' : c.priority === 2 ? '⚡' : '💬';
const prioWord = c.priority === 1 ? 'HOT' : c.priority === 2 ? 'WARM' : 'COOL';
const msg = (d.message || '').slice(0, 300) + ((d.message || '').length > 300 ? '...' : '');
const firstName = c.first_name || (d.name || '').split(' ')[0];

const text = `🌙 AUTO-SENT (outside hours) · ${prio} ${prioWord} ${c.industry_archetype}

${firstName} · ${d.service || 'no service'} · ${c.budget_fit}
${(c.signals || []).slice(0,5).join(', ')}

ASK
${c.summary}

MESSAGE
${msg}

───────
SENT REPLY (Scaffold ${d.draft.scaffold_used}, ${d.draft.confidence} confidence)

${d.draft.subject}

${d.draft.body_plain}

───────
${d.draft.notes_for_isaiah || 'No flags.'} Follow up in the morning.`;

return [{ json: { ...d, telegram_text: text.slice(0, 3900) } }];

